namespace sv_b3568519d77e4923a1c2d57d982bff51.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_b3568519d77e4923a1c2d57d982bff51.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels =
        [
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering topics and code reviews", 0),
            new(3, "design", "Design feedback and assets", 1),
            new(4, "random", "Off-topic and fun stuff", 5),
        ];

        var now = DateTime.UtcNow;
        _messages =
        [
            new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app.", now.AddHours(-3), null, [new("👍", ["Bob", "Carol"])]),
            new(2, 1, "Bob", "Thanks Alice! This looks great.", now.AddHours(-2.5), null, [new("❤️", ["Alice"])]),
            new(3, 1, "Carol", "Love the new design. Any plans for dark mode?", now.AddHours(-2), null, []),
            new(4, 1, "Alice", "Yes! Dark mode is on the roadmap.", now.AddHours(-1.5), 3, [new("🎉", ["Carol", "Bob"])]),
            new(5, 1, "Dave", "Can we also get emoji reactions?", now.AddMinutes(-45), null, [new("😂", ["Alice"]), new("👍", ["Carol"])]),
            new(6, 1, "Bob", "Already have them!", now.AddMinutes(-30), 5, []),
            new(7, 1, "Carol", "Shipping fast 🚀", now.AddMinutes(-10), null, []),
            new(10, 2, "Dave", "PR #42 is ready for review.", now.AddHours(-1), null, []),
            new(11, 2, "Alice", "I'll take a look this afternoon.", now.AddMinutes(-50), null, [new("👍", ["Dave"])]),
            new(12, 3, "Carol", "New mockups uploaded to Figma.", now.AddMinutes(-20), null, [new("❤️", ["Alice", "Bob"])]),
        ];
    }

    public Task<List<Channel>> GetChannelsAsync() =>
        Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take) =>
        Task.FromResult(
            _messages
                .Where(m => m.ChannelId == channelId)
                .OrderBy(m => m.SentAt)
                .Skip(skip)
                .Take(take)
                .ToList());

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(
            Interlocked.Increment(ref _nextMessageId),
            channelId,
            "You",
            content,
            DateTime.UtcNow,
            replyToId,
            []);
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId) =>
        Task.FromResult(
            _messages
                .Where(m => m.ReplyToId == rootMessageId)
                .OrderBy(m => m.SentAt)
                .ToList());

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return Task.CompletedTask;

        var idx = _messages.IndexOf(msg);
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);

        if (existing is not null)
        {
            reactions.Remove(existing);
            if (!existing.Users.Contains("You"))
                reactions.Add(existing with { Users = [.. existing.Users, "You"] });
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        _messages[idx] = msg with { Reactions = reactions };
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var ch = _channels.FirstOrDefault(c => c.Id == channelId);
        if (ch is not null)
        {
            var idx = _channels.IndexOf(ch);
            _channels[idx] = ch with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat

<div class="message-input">
    <textarea class="form-control"
              placeholder="@Placeholder"
              @bind="text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="btn btn-primary" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string text = "";

    private async Task Send()
    {
        var trimmed = text.Trim();
        if (!string.IsNullOrEmpty(trimmed))
        {
            text = "";
            await OnSend.InvokeAsync(trimmed);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #dee2e6;
    background: #fff;
}

.message-input textarea {
    resize: none;
    flex: 1;
}

.message-input button {
    align-self: flex-end;
}

@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat
@using sv_b3568519d77e4923a1c2d57d982bff51.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-top-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-primary rounded-pill">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel);
}

.channel-item {
    padding: 0.6rem 0.75rem;
    cursor: pointer;
    border-radius: 0.375rem;
    margin: 0.15rem 0.5rem;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.2);
}

.channel-top-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.channel-desc {
    font-size: 0.75rem;
    color: rgba(255, 255, 255, 0.6);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat
@using sv_b3568519d77e4923a1c2d57d982bff51.Services

<div class="message-item" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnOpenThread.InvokeAsync(Message)">
                💬 Reply
            </button>
            <button class="btn btn-sm btn-outline-secondary" @onclick="ToggleEmojiPicker">
                😀 React
            </button>
        </div>

        @if (_showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in Emojis)
                {
                    <button class="emoji-option" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    private static readonly string[] Emojis = ["👍", "❤️", "😂", "😮", "😢", "🎉"];

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ShowActions() => _showActions = true;
    private void HideActions() { _showActions = false; _showEmojiPicker = false; }
    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    internal static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

