{"path": "/tmp/sv-b3568519d77e4923a1c2d57d982bff51/Services/MockChatService.cs", "file_text": "namespace sv_b3568519d77e4923a1c2d57d982bff51.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels =
        [
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering topics and code reviews", 0),
            new(3, "design", "Design feedback and assets", 1),
            new(4, "random", "Off-topic and fun stuff", 5),
        ];

        var now = DateTime.UtcNow;
        _messages =
        [
            new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app.", now.AddHours(-3), null, [new("👍", ["Bob", "Carol"])]),
            new(2, 1, "Bob", "Thanks Alice! This looks great.", now.AddHours(-2.5), null, [new("❤️", ["Alice"])]),
            new(3, 1, "Carol", "Love the new design. Any plans for dark mode?", now.AddHours(-2), null, []),
            new(4, 1, "Alice", "Yes! Dark mode is on the roadmap.", now.AddHours(-1.5), 3, [new("🎉", ["Carol", "Bob"])]),
            new(5, 1, "Dave", "Can we also get emoji reactions?", now.AddMinutes(-45), null, [new("😂", ["Alice"]), new("👍", ["Carol"])]),
            new(6, 1, "Bob", "Already have them!", now.AddMinutes(-30), 5, []),
            new(7, 1, "Carol", "Shipping fast 🚀", now.AddMinutes(-10), null, []),
            new(10, 2, "Dave", "PR #42 is ready for review.", now.AddHours(-1), null, []),
            new(11, 2, "Alice", "I'll take a look this afternoon.", now.AddMinutes(-50), null, [new("👍", ["Dave"])]),
            new(12, 3, "Carol", "New mockups uploaded to Figma.", now.AddMinutes(-20), null, [new("❤️", ["Alice", "Bob"])]),
        ];
    }

    public Task<List<Channel>> GetChannelsAsync() =>
        Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take) =>
        Task.FromResult(
            _messages
                .Where(m => m.ChannelId == channelId)
                .OrderBy(m => m.SentAt)
                .Skip(skip)
                .Take(take)
                .ToList());

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(
            Interlocked.Increment(ref _nextMessageId),
            channelId,
            "You",
            content,
            DateTime.UtcNow,
            replyToId,
            []);
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId) =>
        Task.FromResult(
            _messages
                .Where(m => m.ReplyToId == rootMessageId)
                .OrderBy(m => m.SentAt)
                .ToList());

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return Task.CompletedTask;

        var idx = _messages.IndexOf(msg);
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);

        if (existing is not null)
        {
            reactions.Remove(existing);
            if (!existing.Users.Contains("You"))
                reactions.Add(existing with { Users = [.. existing.Users, "You"] });
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        _messages[idx] = msg with { Reactions = reactions };
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var ch = _channels.FirstOrDefault(c => c.Id == channelId);
        if (ch is not null)
        {
            var idx = _channels.IndexOf(ch);
            _channels[idx] = ch with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}
"}

