+@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat
+
+<div class="message-input">
+    <textarea class="form-control"
+              placeholder="@Placeholder"
+              @bind="text"
+              @bind:event="oninput"
+              @onkeydown="HandleKeyDown"
+              rows="2"></textarea>
+    <button class="btn btn-primary" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(text)">
+        @ButtonText
+    </button>
+</div>
+
+@code {
+    [Parameter] public string Placeholder { get; set; } = "Type a message...";
+    [Parameter] public string ButtonText { get; set; } = "Send";
+    [Parameter] public EventCallback<string> OnSend { get; set; }
+
+    private string text = "";
+
+    private async Task Send()
+    {
+        var trimmed = text.Trim();
+        if (!string.IsNullOrEmpty(trimmed))
+        {
+            text = "";
+            await OnSend.InvokeAsync(trimmed);
+        }
+    }
+
+    private async Task HandleKeyDown(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await Send();
+        }
+    }
+}
+

