toolArgs.file_text:
.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.message-author {
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.15rem 0.45rem;
    font-size: 0.8rem;
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    cursor: pointer;
    line-height: 1.3;
}

.reaction-badge:hover {
    background: #dee2e6;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    font-size: 0.8rem;
    color: #0d6efd;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    text-decoration: none;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.75rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.2rem;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    z-index: 10;
}

.message-actions button {
    font-size: 0.75rem;
    padding: 0.15rem 0.4rem;
}

.emoji-picker {
    position: absolute;
    top: 2rem;
    right: 0.75rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    z-index: 11;
}

.emoji-option {
    font-size: 1.25rem;
    cursor: pointer;
    padding: 0.2rem 0.35rem;
    border-radius: 0.25rem;
    background: none;
    border: none;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

