@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat
@using sv_b3568519d77e4923a1c2d57d982bff51.Services

<div class="message-list">
    @if (HasMoreMessages)
    {
        <div class="load-more">
            <button class="btn btn-sm btn-link" @onclick="OnLoadMore">⬆ Load older messages</button>
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadSummary="GetThreadSummary(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
}

