@namespace sv_b3568519d77e4923a1c2d57d982bff51.Components.Chat
@using sv_b3568519d77e4923a1c2d57d982bff51.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary border-0" @onclick="OnClose" aria-label="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="thread-root-author">
                <strong>@RootMessage.Author</strong>
                <span class="text-muted small">@MessageItem.FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="thread-root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="thread-reply-header">
                    <strong>@reply.Author</strong>
                    <span class="text-muted small">@MessageItem.FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="thread-reply-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply..." ButtonText="Reply" OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

.thread-header h6 {
    font-weight: 700;
}

.thread-root {
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

.thread-root-author {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.25rem;
}

.thread-root-content {
    font-size: 0.9rem;
    white-space: pre-wrap;
}

.thread-divider {
    text-align: center;
    padding: 0.4rem;
    font-size: 0.75rem;
    color: #6c757d;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

.thread-reply {
    padding: 0.5rem 1rem;
}

.thread-reply:hover {
    background: #f8f9fa;
}

.thread-reply-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.1rem;
    font-size: 0.9rem;
}

.thread-reply-content {
    font-size: 0.85rem;
    white-space: pre-wrap;
}

