    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    flex: 0 0 20%;
    min-width: 200px;
    max-width: 280px;
    border-right: 1px solid #23272a;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.chat-thread {
    flex: 0 0 25%;
    min-width: 260px;
    max-width: 380px;
    border-left: 1px solid #dee2e6;
}

